DualInferenceEngine::DualInferenceEngine(QObject* parent) 
    : QObject(parent), m_abTestingEnabled(false), m_abRatio(0.7f) {}

DualInferenceEngine::~DualInferenceEngine() {}

bool DualInferenceEngine::loadPrimaryModel(const QString& modelPath) {
    m_primaryModel.engine = std::make_unique<InferenceEngine>();
    bool success = m_primaryModel.engine->loadModel(modelPath);
    m_primaryModel.loaded = success;
    m_primaryModel.path = modelPath;
    emit modelLoaded("primary", success);
    return success;
}

bool DualInferenceEngine::loadSecondaryModel(const QString& modelPath) {
    m_secondaryModel.engine = std::make_unique<InferenceEngine>();
    bool success = m_secondaryModel.engine->loadModel(modelPath);
    m_secondaryModel.loaded = success;
    m_secondaryModel.path = modelPath;
    emit modelLoaded("secondary", success);
    return success;
}

QString DualInferenceEngine::generateResponse(const QString& prompt, const QString& modelId) {
    ModelInstance* model = nullptr;
    
    if (!modelId.isEmpty()) {
        if (modelId == "primary" && m_primaryModel.loaded) {
            model = &m_primaryModel;
        } else if (modelId == "secondary" && m_secondaryModel.loaded) {
            model = &m_secondaryModel;
        }
    } else {
        model = &m_primaryModel; // Default to primary
    }
    
    if (!model || !model->loaded) {
        return "No model available for inference";
    }
    
    auto start = std::chrono::high_resolution_clock::now();
    
    std::vector<int32_t> tokens = model->engine->tokenize(prompt.toStdString());
    std::vector<int32_t> responseTokens = model->engine->generate(tokens, 300);
    QString response = QString::fromStdString(model->engine->detokenize(responseTokens));
    
    auto end = std::chrono::high_resolution_clock::now();
    float latency = std::chrono::duration<float, std::milli>(end - start).count();
    
    updatePerformanceStats(modelId.isEmpty() ? "primary" : modelId, latency);
    emit inferenceCompleted(modelId.isEmpty() ? "primary" : modelId, response);
    
    return response;
}

QJsonObject DualInferenceEngine::generateWithComparison(const QString& prompt) {
    QJsonObject result;
    result["prompt"] = prompt;
    
    if (m_primaryModel.loaded) {
        QString primaryResponse = generateResponse(prompt, "primary");
        result["primary_response"] = primaryResponse;
        result["primary_latency"] = m_primaryModel.avgLatency;
    }
    
    if (m_secondaryModel.loaded) {
        QString secondaryResponse = generateResponse(prompt, "secondary");
        result["secondary_response"] = secondaryResponse;
        result["secondary_latency"] = m_secondaryModel.avgLatency;
    }
    
    emit abTestResult(result);
    return result;
}

void DualInferenceEngine::enableABTesting(bool enabled) {
    m_abTestingEnabled = enabled;
}

void DualInferenceEngine::setABRatio(float primaryRatio) {
    m_abRatio = std::clamp(primaryRatio, 0.0f, 1.0f);
}

void DualInferenceEngine::updatePerformanceStats(const QString& modelId, float latency) {
    ModelInstance* model = nullptr;
    if (modelId == "primary") {
        model = &m_primaryModel;
    } else if (modelId == "secondary") {
        model = &m_secondaryModel;
    }
    
    if (model) {
        model->inferenceCount++;
        model->avgLatency = (model->avgLatency * (model->inferenceCount - 1) + latency) / model->inferenceCount;
    }
}

